import React from 'react';
import { Globe, Sun, Moon } from 'lucide-react';

interface LoginProps {
  onLogin: () => void;
  lang: 'pt' | 'en';
  theme: 'light' | 'dark';
  setLang: (lang: 'pt' | 'en') => void;
  setTheme: (theme: 'light' | 'dark') => void;
}

const TRANSLATIONS = {
  pt: {
    loginTitle: "Acesse sua Conta",
    user: "Usuário",
    pass: "Senha",
    loginBtn: "Entrar"
  },
  en: {
    loginTitle: "Access your Account",
    user: "User",
    pass: "Password",
    loginBtn: "Login"
  }
};

const Login: React.FC<LoginProps> = ({ onLogin, lang, theme, setLang, setTheme }) => {
  const t = TRANSLATIONS[lang];

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    onLogin();
  };

  return (
    <div className={`min-h-screen flex items-center justify-center p-4 ${theme === 'dark' ? 'bg-slate-900 text-white' : 'bg-slate-100 text-slate-800'}`}>
      <div className={`w-full max-w-md p-8 rounded-2xl shadow-xl border ${theme === 'dark' ? 'bg-slate-800 border-slate-700' : 'bg-white border-slate-200'}`}>
        <div className="flex justify-center mb-6">
          <div className="w-16 h-16 bg-blue-600 rounded-full flex items-center justify-center text-white text-2xl font-bold">en</div>
        </div>
        <h1 className="text-2xl font-bold text-center mb-8">{t.loginTitle}</h1>
        <form onSubmit={handleLogin} className="space-y-4">
          <div>
            <label className="block text-sm font-medium mb-1 opacity-70">{t.user}</label>
            <input 
              type="text" 
              defaultValue="Admin"
              className={`w-full px-4 py-3 rounded-lg border focus:ring-2 focus:ring-blue-500 outline-none transition-all ${theme === 'dark' ? 'bg-slate-700 border-slate-600' : 'bg-slate-50 border-slate-300'}`}
            />
          </div>
          <div>
            <label className="block text-sm font-medium mb-1 opacity-70">{t.pass}</label>
            <input 
              type="password" 
              defaultValue="Admin"
              className={`w-full px-4 py-3 rounded-lg border focus:ring-2 focus:ring-blue-500 outline-none transition-all ${theme === 'dark' ? 'bg-slate-700 border-slate-600' : 'bg-slate-50 border-slate-300'}`}
            />
          </div>
          <button className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-lg shadow-lg transition-all active:scale-95">
            {t.loginBtn}
          </button>
        </form>
        <div className="mt-6 flex justify-center gap-4">
           <button onClick={() => setLang(lang === 'pt' ? 'en' : 'pt')} className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors">
             <Globe size={20} />
           </button>
           <button onClick={() => setTheme(theme === 'dark' ? 'light' : 'dark')} className="p-2 rounded-full hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors">
             {theme === 'dark' ? <Sun size={20} /> : <Moon size={20} />}
           </button>
        </div>
      </div>
    </div>
  );
};

export default Login;
